/**
 * Resolve a sequence of path segments against an object.
 *
 * Lookup order at each segment:
 *   1. Direct own-property hit (record[seg]).
 *   2. kebab-case to camelCase fallback (e.g. "balance-history" -> "balanceHistory").
 *   3. Otherwise: throw SteleRuntimeError.
 *
 * Mirrors the contract path semantics defined by the Python backend; see
 * docs/spec/cdl.md "Path semantics".
 */
export function steleGetPath(obj: unknown, segments: readonly string[]): unknown {
  let current: unknown = obj;
  for (const seg of segments) {
    if (current === null || current === undefined) {
      throw new SteleRuntimeError(`Path not found: segment "${seg}" on null/undefined`);
    }
    if (Array.isArray(current)) {
      throw new SteleRuntimeError(
        `Path navigation hit array at "${seg}"; arrays must be navigated via collection operators`,
      );
    }
    if (typeof current !== "object") {
      throw new SteleRuntimeError(`Path navigation hit primitive at "${seg}"`);
    }
    const record = current as Record<string, unknown>;
    if (Object.prototype.hasOwnProperty.call(record, seg)) {
      current = record[seg];
      continue;
    }
    const camel = seg.replace(/-([a-z])/g, (_match, ch: string) => ch.toUpperCase());
    if (camel !== seg && Object.prototype.hasOwnProperty.call(record, camel)) {
      current = record[camel];
      continue;
    }
    throw new SteleRuntimeError(`Path not found: "${seg}" missing on object`);
  }
  return current;
}

/**
 * Deep-equality comparison with numeric tolerance.
 *
 * - Identical references compare equal.
 * - Two numbers compare equal when |a - b| <= 1e-9 OR (NaN, NaN).
 * - Arrays compare element-wise.
 * - Plain objects compare by sorted-key set then per-key.
 * - All other types fall back to strict equality.
 */
export function steleEq(a: unknown, b: unknown): boolean {
  if (a === b) {
    return true;
  }
  if (typeof a === "number" && typeof b === "number") {
    if (Number.isNaN(a) && Number.isNaN(b)) {
      return true;
    }
    return Math.abs(a - b) <= 1e-9;
  }
  if (a === null || b === null || a === undefined || b === undefined) {
    return false;
  }
  if (Array.isArray(a) && Array.isArray(b)) {
    if (a.length !== b.length) {
      return false;
    }
    for (let i = 0; i < a.length; i += 1) {
      if (!steleEq(a[i], b[i])) {
        return false;
      }
    }
    return true;
  }
  if (typeof a === "object" && typeof b === "object" && !Array.isArray(a) && !Array.isArray(b)) {
    const aRec = a as Record<string, unknown>;
    const bRec = b as Record<string, unknown>;
    const aKeys = Object.keys(aRec).sort();
    const bKeys = Object.keys(bRec).sort();
    if (aKeys.length !== bKeys.length) {
      return false;
    }
    for (let i = 0; i < aKeys.length; i += 1) {
      if (aKeys[i] !== bKeys[i]) {
        return false;
      }
    }
    for (const key of aKeys) {
      if (!steleEq(aRec[key], bRec[key])) {
        return false;
      }
    }
    return true;
  }
  return false;
}

export function steleNeq(a: unknown, b: unknown): boolean {
  return !steleEq(a, b);
}

