/**
 * Internal length helper used by has-length / is-empty. Distinct from the
 * public `steleLength` operator (EP04) which only accepts collections; this
 * variant accepts arrays, strings, and plain objects to preserve Phase B
 * has-length / is-empty semantics on multi-shape inputs.
 */
function polymorphicLength(label: string, value: unknown): number {
  if (Array.isArray(value)) {
    return value.length;
  }
  if (typeof value === "string") {
    return value.length;
  }
  if (value !== null && typeof value === "object") {
    return Object.keys(value as Record<string, unknown>).length;
  }
  throw new SteleRuntimeError(`${label}: cannot compute length of ${describeType(value)}`);
}

/**
 * Container membership. Mirrors Python's `value in container` for sequences
 * and strings. Object containers test against own-key set.
 */
export function steleExistsIn(value: unknown, container: unknown): boolean {
  if (Array.isArray(container)) {
    for (const candidate of container) {
      if (steleEq(candidate, value)) {
        return true;
      }
    }
    return false;
  }
  if (typeof container === "string") {
    if (typeof value !== "string") {
      throw new SteleRuntimeError(
        `exists-in: cannot test ${describeType(value)} membership in a string container`,
      );
    }
    return container.includes(value);
  }
  if (container !== null && typeof container === "object") {
    if (typeof value !== "string") {
      return false;
    }
    return Object.prototype.hasOwnProperty.call(container, value);
  }
  throw new SteleRuntimeError(
    `exists-in: container must be array, string, or object; got ${describeType(container)}`,
  );
}

